// Fix: dak/kat/dong/nam roots incorrectly carrying raka (·) per THANGSENG Rule 1.
// compiled_dict.json is a BUILD ARTIFACT regenerated by prepare-data.js from the
// source dictionaries below — fixes must be applied at the source, not there.
const fs = require('fs');
const SOURCE_FILES = [
  '/home/claude/lean-garo/master_dictionary.json',
  '/home/claude/lean-garo/garo_dictionary.json',
  '/home/claude/lean-garo/doc7_entries.json',
  '/home/claude/lean-garo/final_entries.json',
  '/home/claude/lean-garo/sentences200.json',
  '/home/claude/lean-garo/src/data/corrections.json',
];

const patterns = [
  { re: /dak·/g, to: 'dak' },
  { re: /kat·/g, to: 'kat' },
  { re: /dong·/g, to: 'dong' },
  { re: /nam·a\b/g, to: 'nama' },
];

let totalFixed = 0;
const allChanges = [];
for (const filePath of SOURCE_FILES) {
  if (!fs.existsSync(filePath)) { console.log('skip (missing):', filePath); continue; }
  const raw = fs.readFileSync(filePath, 'utf8');
  let d;
  try { d = JSON.parse(raw); } catch (e) { console.log('skip (bad json):', filePath); continue; }
  const backupPath = '/tmp/' + filePath.split('/').pop() + '.backup_' + Date.now();
  fs.writeFileSync(backupPath, raw);

  let fileFixed = 0;
  function walk(obj, keyPath) {
    if (typeof obj === 'string') {
      let updated = obj;
      for (const p of patterns) updated = updated.replace(p.re, p.to);
      if (updated !== obj) {
        allChanges.push({ file: filePath, key: keyPath, before: obj, after: updated });
        fileFixed++;
        return updated;
      }
      return obj;
    }
    if (Array.isArray(obj)) return obj.map((v, i) => walk(v, keyPath + '[' + i + ']'));
    if (obj && typeof obj === 'object') {
      const out = {};
      for (const k in obj) out[k] = walk(obj[k], keyPath ? keyPath + '.' + k : k);
      return out;
    }
    return obj;
  }
  const fixed = walk(d, '');
  if (fileFixed > 0) {
    fs.writeFileSync(filePath, JSON.stringify(fixed, null, 2));
    console.log(filePath, '-> backup:', backupPath, '-> fixed:', fileFixed);
  } else {
    console.log(filePath, '-> no violations found');
  }
  totalFixed += fileFixed;
}

fs.writeFileSync('/tmp/raka_fix_log.json', JSON.stringify(allChanges, null, 1));
console.log('TOTAL fixed across source files:', totalFixed);
